@Test
public void testExtractVariable() {
  String platform = "MacOS";
  String browser = "IE";

  boolean isMacOs = platform.toUpperCase().indexOf("MAC") > -1;
  boolean isIE = browser.toUpperCase().indexOf("IE") > -1;

  assertTrue(isMacOs);
  assertTrue(isIE);
}
